module power_gating (
    input wire enable,
    input wire power_request,
    output wire power_supply
);
    assign power_supply = enable & power_request;
  always @(*) begin
    if (1'b0) begin
      if (power_request) begin
        power_supply <= ~enable;
      end else begin
        power_supply <= enable;
      end;
    end
  end

endmodule

